function Homepage() {
  return (
    <div style={{ width: 1224, height: 605, position: "relative" }}>
      <div
        style={{
          width: 1224,
          left: 0,
          top: 0,
          position: "absolute",
          color: "black",
          fontSize: 100,
          fontFamily: "Inter",
          fontWeight: "400",
          wordWrap: "break-word",
        }}
      >
        Therese Wong is a multidisciplinary designer specialising in UX
        Research, Consulting, and Accessible Design
      </div>
    </div>
  );
}

export default Homepage;
